## 组件

### 创建组件

#### 外部组件

```javascript

//创建方式一
var myComponent=Vue.extend({
    template:"<h2>Hello world</h2>"
});
Vue.component("firstcom",myComponent);

//创建方式二
Vue.component("myvue",{
    template:"<h2>你好 VUE</h2>"
});
var app = new Vue({ 
    el: '#app',
    data: {
        message: 'Hello Vue!'
    }
});

```

```html
 <div id="app">
    <myvue></myvue>
    <firstcom></firstcom>
</div>

```
效果如下：

![图片](https://raw.githubusercontent.com/TaffyBlog/TaffyBlog.github.io/master/images/comon1.png)


#### 局部组件

```javascript
var app = new Vue({ 
    el: '#app',
    data: {
        message: 'Hello Vue!'
    },
    components:{
        "firstcom":{
             template:"<h2>Hello world</h2>"
        },
        "myvue":{
            template:"<h2>你好 VUE</h2>"
        }
    }
});

```

> 注意有`s`

### 使用数据

```javascript
var app = new Vue({ 
    el: '#app',
    data: {
        message: 'Hello Vue!'
    },
    components:{
        "myvue":{
            template:"<h2>{{name}}</h2>",
            data:function()
            {
                return {
                    name:"张三"
                }
            }
        }
       
    }
});

```

> 每个组件都是独立的，不能直接使用`vue`实例中的数据。**一个组件的 `data` 选项必须是一个函数**

