## 解构数组

### 变量声明并赋值时的解构

```javascript
var foo = ["one", "two", "three"];

var [one, two, three] = foo;
console.log(one); // "one"
console.log(two); // "two"
console.log(three); // "three"
```
### 变量先声明后赋值时的解构

```javascript
var a, b;

[a, b] = [1, 2];
console.log(a); // 1
console.log(b); // 2
```
### 默认值
```javascript
//为了防止从数组中取出一个值为undefined的对象，可以为这个对象设置默认值。
var a, b;

[a = 5, b = 7] = [1];
console.log(a); // 1
console.log(b); // 7
```
### 交换变量

1. 在一个解构表达式中可以交换两个变量的值。

2. 没有解构赋值的情况下，交换两个变量需要一个临时变量。

```javascript

var a = 1;
var b = 3;

[a, b] = [b, a];
console.log(a); // 3
console.log(b); // 1
```

### 解析一个从函数返回的数组

> 从一个函数返回一个数组是十分常见的情况.。解构使得处理返回值为数组时更加方便。

在下面例子中，`[1, 2]` 作为函数的`f()` 的输出值，可以使用解构用一句话完成解析:

```javascript

function f() {
    return [1, 2];
}

var a, b;
[a, b] = f();
console.log(a); // 1
console.log(b); // 2
```
#### 忽略某些返回值

> 你也可以忽略你不感兴趣的返回值：
```javascript
function f() {
    return [1, 2, 3];
}

var [a, , b] = f();
console.log(a); // 1
console.log(b); // 3

```
### 将剩余数组赋值给一个变量

> 当解构一个数组时，可以使用剩余模式，将数组剩余部分赋值给一个变量。

```javascript
var [a, ...b] = [1, 2, 3];
console.log(a); // 1
console.log(b); // [2, 3]

```
> 注意：如果剩余元素右侧有一个逗号，会抛出SyntaxError，因为剩余元素必须是数组的最后一个元素。

### 用正则表达式匹配提取值

> 用正则表达式方法exec()匹配字符串会返回一个数组，该数组第一个值是完全匹配正则表达式的字符串，然后的值是匹配正则表达式括号内内容部分。解构赋值允许你轻易地提取出需要的部分，忽略完全匹配的字符串——如果不需要的话
```javascript
var url = "https://developer.mozilla.org/en-US/Web/JavaScript";

var parsedURL = /^(\w+)\:\/\/([^\/]+)\/(.*)$/.exec(url);
console.log(parsedURL); // ["https://developer.mozilla.org/en-US/Web/JavaScript", "https", "developer.mozilla.org", "en-US/Web/JavaScript"]

var [, protocol, fullhost, fullpath] = parsedURL;

console.log(protocol); // "https"
```
## 解构对象

### 基本赋值
```javascript
var o = { p: 42, q: true };
var { p, q } = o;

console.log(p); // 42
console.log(q); // true
```
### 无声明赋值
```javascript
var a, b;

({ a, b } = { a: 1, b: 2 });
```

1. 赋值语句周围的( .. ) 是使用对象字面解构赋值时不需要声明的语法。
2. { a, b } = { a: 1, b: 2 } 不是有效的独立语法，因为左边的{a, b }
3. 被认为是一个块而不是对象字面量。然而，({ a, b } = { a: 1, b: 2 })
4. 是有效的，正如 var { a, b } = { a: 1, b: 2 }
5. 注意：你的( .. ) 表达式需要一个分号在它前面，否则它也许会被当成上一行中的函数来执行。

### 给新的变量名赋值

> 可以从一个对象中提取变量并赋值给和对象属性名不同的新的变量名。自定义变量名/重新定义变量名

```javascript
//p和q只是一个模式匹配

var o = { p: 42, q: true };
var { p: foo, q: bar } = o;

console.log(foo); // 42 
console.log(bar); // true
```
### 默认值

> 变量可以先赋予默认值。当要提取的对象没有对应的属性，变量就被赋予默认值。

```javascript
var { a = 10, b = 5 } = { a: 3 };

console.log(a); // 3
console.log(b); // 5
```
#### 给新的变量命名并提供默认值

> 一个属性可以是从一个对象解构，并分配给一个不同名称的变量，分配一个默认值，以防未解构的值是undefined。

```javascript
var { a: aa = 10, b: bb = 5 } = { a: 3 };

console.log(aa); // 3
console.log(bb); // 5

```
#### 函数参数默认值

```javascript
//ES5版本
function drawES5Chart(options) {
    options = options === undefined ? {} : options;
    var size = options.size === undefined ? 'big' : options.size;
    var cords = options.cords === undefined ? { x: 0, y: 0 } : options.cords;
    var radius = options.radius === undefined ? 25 : options.radius;
    console.log(size, cords, radius);
    // now finally do some chart drawing
}

drawES5Chart({
    cords: { x: 18, y: 30 },
    radius: 30
});

//ES6版本
function drawES2015Chart({ size = 'big', cords = { x: 0, y: 0 }, radius = 25 } = {}) {
    console.log(size, cords, radius);
    // do some chart drawing
}

drawES2015Chart({
    cords: { x: 18, y: 30 },
    radius: 30
});
```
1. 在上面的drawES2015Chart的函数签名中，解构的左手边被分配给右手边的空对象字面值：{ size = 'big', cords = { x: 0, y: 0 }, radius = 25 } = { } 。
2. 你也可以在没有右侧分配的情况下编写函数。
3. 但是，如果你忽略了右边的赋值，那么函数会在被调用的时候查找至少一个被提供的参数，而在当前的形式下，你可以直接调用drawES2015Chart()而不提供任何参数。
4. 如果你希望能够在不提供任何参数的情况下调用该函数，则当前的设计非常有用，而另一种方法在您确保将对象传递给函数时非常有用。


