## 自定义解析器

在ef中，我们可以使用lambda表达式进行数据库操作，但是最后到数据库执行的一定是sql语句，而表达式树解析正好可以满足这个需求。

示例如下:

解析器需要继承`ExpressionVisitor`,这是一个抽象类，定义了许多虚方法以供我们重写，本例中重写了`VisitBinary`、`VisitMember`、`VisitMethodCall`方法；每个表达式解析完成后自动解析下一个表达式，直到遍历解析完整个表达式树。

```java

 public class ConditionBuilderVisitor : ExpressionVisitor
{
    private Stack<string> _StringStack = new Stack<string>();

    public string Condition()
    {
        string condition = string.Concat(this._StringStack.ToArray());
        this._StringStack.Clear();
        return condition;
    }

    /// <summary>
    /// 如果是二元表达式
    /// </summary>
    /// <param name="node"></param>
    /// <returns></returns>
    protected override Expression VisitBinary(BinaryExpression node)
    {
        if (node == null) throw new ArgumentNullException("BinaryExpression");

        this._StringStack.Push(")");
        base.Visit(node.Right);//解析右边
        this._StringStack.Push(" " + node.NodeType.ToSqlOperator() + " ");
        base.Visit(node.Left);//解析左边
        this._StringStack.Push("(");

        return node;
    }
    /// <summary>
    /// 如果是属性或字段
    /// </summary>
    /// <param name="node"></param>
    /// <returns></returns>
    protected override Expression VisitMember(MemberExpression node)
    {
        if (node == null) throw new ArgumentNullException("MemberExpression");
        this._StringStack.Push(" [" + node.Member.Name + "] ");
        return node;
    }
    /// <summary>
    /// 常量表达式
    /// </summary>
    /// <param name="node"></param>
    /// <returns></returns>
    protected override Expression VisitConstant(ConstantExpression node)
    {
        if (node == null) throw new ArgumentNullException("ConstantExpression");
        this._StringStack.Push(" '" + node.Value + "' ");
        return node;
    }
    /// <summary>
    /// 方法表达式
    /// </summary>
    /// <param name="m"></param>
    /// <returns></returns>
    protected override Expression VisitMethodCall(MethodCallExpression m)
    {
        if (m == null) throw new ArgumentNullException("MethodCallExpression");

        string format;
        switch (m.Method.Name)
        {
            case "StartsWith":
                format = "({0} LIKE {1}+'%')";
                break;

            case "Contains":
                format = "({0} LIKE '%'+{1}+'%')";
                break;

            case "EndsWith":
                format = "({0} LIKE '%'+{1})";
                break;
            case "Equals":
                    format = "({0} =  '{1}')";
                    break;
            default:
                throw new NotSupportedException(m.NodeType + " is not supported!");
        }
        this.Visit(m.Object);
        this.Visit(m.Arguments[0]);
        string right = this._StringStack.Pop();
        string left = this._StringStack.Pop();
        this._StringStack.Push(String.Format(format, left, right));

        return m;
    }
  
}

```

扩展方法类:

```java
 internal static class SqlOperator
{
     /// <summary>
    /// 扩展方法 转换运算符
    /// </summary>
    /// <param name="type"></param>
    /// <returns></returns>
    internal static string ToSqlOperator(this ExpressionType type)
    {
        switch (type)
        {
            case (ExpressionType.AndAlso):
            case (ExpressionType.And):
                return "AND";
            case (ExpressionType.OrElse):
            case (ExpressionType.Or):
                return "OR";
            case (ExpressionType.Not):
                return "NOT";
            case (ExpressionType.NotEqual):
                return "<>";
            case ExpressionType.GreaterThan:
                return ">";
            case ExpressionType.GreaterThanOrEqual:
                return ">=";
            case ExpressionType.LessThan:
                return "<";
            case ExpressionType.LessThanOrEqual:
                return "<=";
            case (ExpressionType.Equal):
                return "=";
            default:
                throw new Exception("不支持该方法");
        }

    }
}
```

