## 创建枚举器
yield return 语句返回集合的一个元素，并移动到下一个元素上。yield break可停止迭代
```java
class Program
{
	static void Main(string[] args)
	{
		TestCollection c = new TestCollection();
		c.Add("Hello");
		c.Add("World");
		foreach (var item in c)
		{
			Console.Write(item);
		}
	}
}
/// <summary>
/// 自定义集合类
/// </summary>
class TestCollection
{
	List<string> list = new List<string>();
	public void Add(string s)
	{
		list.Add(s);
	}
	public IEnumerator<string> GetEnumerator()
	{
		foreach (var item in list)
		{
			yield return item;
		}
	}
}
```
类支持的默认迭代是定义为返回IEnumerator的GetEnumerator方法。自定义命名的迭代返回IEnumerable(如：将数组逆序迭代)


## yield return语句返回一个枚举器
```java
class Program
{
	static void Main(string[] args)
	{
		TestCollection c = new TestCollection();
		IEnumerator enumerator = c.Cross();

		while (enumerator.MoveNext())
		{
			enumerator = enumerator.Current as IEnumerator;//将enumerator的值设为当前的枚举器，用于下一次循环
		}
	}
}
/// <summary>
/// 自定义集合类
/// </summary>
class TestCollection
{
	private IEnumerator cross;
	private IEnumerator circle;
	private int move = 0;
	private int maxmove = 9;
	public TestCollection()
	{
		cross = Cross();
		circle = Circle();
	}
	//定义两个IEnumerator的方法，各自返回对方的枚举器
	public IEnumerator Cross()
	{
		while (true)
		{
			Console.WriteLine("Corross, move {0}",move);
			if (++move>=maxmove)
			{
				yield break;
			}
			yield return circle;
		}
	}
	public IEnumerator Circle()
	{
		while (true)
		{
			Console.WriteLine("Circle, move {0}",move);
			if (++move>=maxmove)
			{
				yield break;
			}
			yield return cross;
		}
	}
}
```
结果:交替输出1-8
